const crypto = require('crypto');
const body = JSON.stringify($input.first().json.body || $input.first().json);
const sig = $input.first().json.headers?.['x-hub-signature-256'] || '';
const expected = 'sha256=' + crypto.createHmac('sha256', $env.WHATSAPP_APP_SECRET).update(body).digest('hex');

if (sig !== expected) {
  throw new Error('Invalid webhook signature');
}

return $input.all();

