  }
}];

// Build system prompt dynamically from playbook + coupons
const playbook = $node['Get NV Playbook'].json || [];
const playbookArr = Array.isArray(playbook) ? playbook : [];

// Cache the playbook
const cache = $getWorkflowStaticData('global');
cache.playbook = playbookArr;
cache.playbook_ts = Date.now();

// --- Coupon data ---
const couponConfigRaw = $node['Fetch Coupon Config'].json || [];
const couponConfigArr = Array.isArray(couponConfigRaw) ? couponConfigRaw : [];
const cfgMap = {};
couponConfigArr.forEach(c => cfgMap[c.key] = c.value);

const couponEnabled = cfgMap.coupon_enabled === 'true';
const couponOfferStage = cfgMap.coupon_offer_stage || 'closing';
const couponOfferMessage = cfgMap.coupon_offer_message || '';

const activeCouponsRaw = $node['Fetch Active Coupons'].json || [];
const couponsArr = Array.isArray(activeCouponsRaw) ? activeCouponsRaw : [];
const validCoupons = couponsArr.filter(c => !c.max_uses || (c.current_uses || 0) < c.max_uses);

// --- Base prompt ---
const BASE_PROMPT = `Sos NovaBot, asistente de ventas de NovaVision.
NovaVision ofrece tiendas online llave en mano para pymes argentinas.

REGLAS ABSOLUTAS:
1. NUNCA inventar precios. Usar SOLO los del PRICING recibido.
2. NUNCA mencionar montos en USD al lead. Solo ARS.
3. Máximo 3 mensajes seguidos del bot sin respuesta del lead → dejar de insistir.
4. Si el lead dice "no" claramente → respetar y despedirse amablemente.
5. Si el lead pide hablar con un humano → decir que un asesor se comunicará pronto.
6. Responder SIEMPRE en español argentino informal pero profesional.
7. Mensajes cortos (máx 300 chars) para WhatsApp.

OBJETIVO: Llevar al lead a iniciar su tienda gratuita en el builder.
URL del builder: https://novavision.com.ar/builder

FORMATO DE RESPUESTA (JSON estricto):
{
  "reply": "texto del mensaje",
  "engagement_delta": -10 a +20,
  "conversation_stage": "INTRO|DISCOVERY|FOLLOWUP|CLOSING|DEMO_OFFERED",
  "intent": "interested|curious|objection|not_interested|spam|human_request",
  "should_notify_sales": true/false,
  "coupon_code_offered": "CÓDIGO" o null,
  "reasoning": "explicación interna"
}`;

const sections = playbookArr
  .sort((a, b) => (a.priority || 0) - (b.priority || 0))
  .map(p => `### ${p.title}\n${p.content}`)
  .join('\n\n');

// --- Coupon section for prompt ---
let couponSection = '';
if (couponEnabled && validCoupons.length > 0) {
  const couponList = validCoupons.map(c => {
    const desc = c.discount_type === 'percent'
      ? `${c.discount_value}% de descuento`
      : c.discount_type === 'free_setup'
        ? 'Setup GRATIS'
        : `$${c.discount_value} de descuento`;
    return `- Código: ${c.code} → ${desc}. ${c.description || ''}`;
  }).join('\n');

  couponSection = `\n\n## CUPONES DISPONIBLES\nTenés cupones de descuento para ofrecer como incentivo de cierre.\n\nREGLAS DE CUPONES:\n1. Ofrecer cupón SOLO cuando la conversación esté en stage "${couponOfferStage}" o superior (CLOSING, DEMO_OFFERED).\n2. NO ofrecer cupón en la primera interacción ni en INTRO/DISCOVERY.\n3. Ofrecer cupón cuando el lead muestre objeciones de precio o dude en contratar.\n4. Máximo 1 cupón por conversación. Si CUPÓN YA OFRECIDO = SÍ, NO repetir.\n5. Cuando ofrezcas un cupón, poné el código en "coupon_code_offered".\n6. Si NO ofrecés cupón, dejá "coupon_code_offered": null.\n${couponOfferMessage ? 'MENSAJE SUGERIDO: ' + couponOfferMessage + '\n' : ''}\nCUPONES ACTIVOS:\n${couponList}`;
} else {
  couponSection = '\n\n## CUPONES\nNo hay cupones disponibles. Dejá "coupon_code_offered": null siempre.';
}

const fullPrompt = BASE_PROMPT + '\n\n## PLAYBOOK\n' + (sections || '(sin playbook)') + couponSection;

return [{ json: { system_prompt: fullPrompt, coupon_enabled: couponEnabled, valid_coupons: validCoupons } }];

const lead = $node['Lead Found Check'].json.lead || {};
const inbound = $node['Check Opt-out'].json;
const history = $node['Get Conversation History'].json || [];
const historyArr = Array.isArray(history) ? history : [];
