const botEnabled = lead.bot_enabled !== false;

const historyText = historyArr
  .reverse()
  .map(h => `${h.direction}: ${h.message_text}`)
  .join('\n');

// Check if coupon was already offered in conversation history
const couponCodes = (promptData.valid_coupons || []).map(c => c.code);
const couponAlreadyOffered = historyArr.some(h =>
  h.direction === 'BOT' && h.message_text &&
  (couponCodes.some(code => h.message_text.includes(code)) || h.message_text.toLowerCase().includes('cupón'))
);

return [{
  json: {
    bot_enabled: botEnabled,
    lead_id: lead.id,
    lead_name: lead.name || inbound.contact_name,
    lead_company: lead.company || '',
    lead_status: lead.status || 'IN_CONVERSATION',
