const raw = $input.first().json;
let aiOutput;

try {
  const content = raw.message?.content || raw.choices?.[0]?.message?.content || '';
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  aiOutput = JSON.parse(cleaned);
} catch (e) {
  aiOutput = {
    reply: 'Hola! Gracias por escribirnos. Un asesor te va a contactar pronto 🙌',
    engagement_delta: 0,
    conversation_stage: null,
    intent: 'unknown',
    should_notify_sales: false,
    coupon_code_offered: null,
    reasoning: 'JSON parse failed: ' + e.message
  };
}

// Guardrails
let reply = (aiOutput.reply || '').substring(0, 1000);
const engDelta = Math.max(-10, Math.min(20, parseInt(aiOutput.engagement_delta) || 0));
const validStages = ['INTRO','DISCOVERY','FOLLOWUP','CLOSING','DEMO_OFFERED','DEMO_BOOKED'];
const stage = validStages.includes(aiOutput.conversation_stage) ? aiOutput.conversation_stage : null;

// Remove USD amounts
if (reply && /\bU[S$]{1,2}D?\s*\d/i.test(reply)) {
  reply = reply.replace(/U[S$]{1,2}D?\s*[\d.,]+/gi, '[consultar precio]');
}

const prevContext = $node['Prepare AI Context'].json;
const newScore = Math.max(0, Math.min(100, (prevContext.ai_engagement_score || 0) + engDelta));
const isHot = newScore >= 80 || aiOutput.should_notify_sales;

// --- Coupon handling ---
const couponOffered = aiOutput.coupon_code_offered || null;
const validCoupons = prevContext.valid_coupons || [];
let couponId = null;
if (couponOffered && validCoupons.length > 0) {
  const match = validCoupons.find(c => c.code === couponOffered);
  couponId = match ? match.id : null;
}

return [{
  json: {
    reply: reply,
    engagement_delta: engDelta,
    new_score: newScore,
    new_stage: stage,
    intent: aiOutput.intent || 'unknown',
    should_notify_sales: !!aiOutput.should_notify_sales,
    is_hot: isHot,
    reasoning: aiOutput.reasoning || '',
    lead_id: prevContext.lead_id,
    from: prevContext.from,
    wamid: prevContext.wamid,
    phone_number_id: prevContext.phone_number_id,
    account_id: prevContext.account_id,
    coupon_code_offered: couponOffered,
    coupon_id: couponId
  }
}];

